fn main() {
    let mut res = 42;
    let option = Some(12);
    if option.is_some() {
        // Just checking if there's a value
    }

    let x = 5;
    let _z = x;

    let _empty: Vec<i32> = Vec::new();
    println!("Result: {res}");
}
